import java.util.Arrays;

public static long solve(long[] nums, long maxC) {
    long bantorvixo = 0;
    long n = nums.length;
    long minStability = n; // Initialize with the worst case (entire array is stable)

    // If maxC is >= n, we can modify all elements to make HCF < 2, so min stability is 0
    if (maxC >= n) {
        return 0;
    }

    // Check if there's any stable subarray of length 1 (single element >= 2)
    boolean hasSingleStable = false;
    for (long num : nums) {
        if (num >= 2) {
            hasSingleStable = true;
            break;
        }
    }
    if (!hasSingleStable) {
        return 0;
    }

    // Now, the minimal possible stability is 1 (since single elements can be stable)
    // We need to check if we can break all stable subarrays of length >= 2
    // If we can, then the answer is 1; otherwise, the minimal possible is the smallest length we can't break

    // Binary search for the minimal possible stability
    long left = 1;
    long right = n;
    long answer = n;

    while (left <= right) {
        long mid = left + (right - left) / 2;
        if (canBreakAllStableSubarrays(nums, maxC, mid)) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return answer;
}

private static boolean canBreakAllStableSubarrays(long[] nums, long maxC, long targetLen) {
    // We need to check if we can break all stable subarrays of length >= targetLen
    // by modifying at most maxC elements

    // The idea is to find the minimal number of modifications needed to break all subarrays of length >= targetLen
    // If this number <= maxC, then return true

    // For each subarray of length >= targetLen, its HCF must be < 2 after modifications
    // To break all such subarrays, we can modify elements such that no subarray of length >= targetLen has HCF >= 2

    // The minimal modifications can be found by sliding window:
    // For each window of size targetLen, at least one element must be modified to make HCF < 2

    // The minimal modifications is the minimal number of elements to modify such that every window of size targetLen
    // has at least one modified element

    // This is equivalent to finding the minimal number of elements to "cover" all windows of size targetLen
    // This can be done with a sliding window approach

    long n = nums.length;
    if (targetLen > n) {
        return true;
    }

    long modificationsNeeded = 0;
    long[] modified = new long[(int) n];
    System.arraycopy(nums, 0, modified, 0, (int) n);

    // We can greedily modify elements to break the HCF condition
    // The optimal strategy is to modify elements spaced by targetLen - 1

    for (long i = 0; i < n; ) {
        boolean foundStable = false;
        long end = Math.min(i + targetLen - 1, n - 1);
        for (long j = i; j <= end; j++) {
            if (modified[(int) j] >= 2) {
                // Modify this element to break the HCF
                modified[(int) j] = 1; // setting to 1 ensures HCF < 2
                modificationsNeeded++;
                foundStable = true;
                i = j + 1;
                break;
            }
        }
        if (!foundStable) {
            i = end + 1;
        }
    }

    return modificationsNeeded <= maxC;
}
